const API = "http://localhost:8080/";

// Hàm GET
export const get = async (path) => {
  try {
    const response = await fetch(API + path, {
      method: "GET",
      headers: {
        Accept: "application/json",
      },
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }

    const result = await response.json();
    return result;
  } catch (error) {
    console.error("Error in GET request:", error.message);
    throw error;
  }
};

// Hàm POST
export const post = async (path, data) => {
  try {
    const response = await fetch(API + path, {
      method: "POST",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
      },
      body: JSON.stringify(data),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }

    const result = await response.text();
    return result;
  } catch (error) {
    console.error("Error in POST request:", error.message);

    throw error;
  }
};

export const fetchWithAuth = async (path, method = "GET", body = null) => {
  const username = localStorage.getItem("username"); // Lấy username từ localStorage hoặc cookie
  const password = localStorage.getItem("password"); // Lấy password từ localStorage hoặc cookie
  const authHeader = "Basic " + btoa(`${username}:${password}`); // Mã hóa Base64

  const headers = {
    "Authorization": authHeader,
    "Content-Type": "application/json",
  };

  const options = {
    method,
    headers,
  };

  if (body) {
    options.body = JSON.stringify(body); // Thêm body nếu là POST/PUT
  }

  const response = await fetch(`http://localhost:8080${path}`, options);

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
  }

  return await response.json();
};


export const register = async (options) => {
  try {
    const response = await fetch(`${API}api/auth/register`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(options),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }

    return await response.json(); // Phân tích dữ liệu JSON từ phản hồi
  } catch (error) {
    console.error("Lỗi khi gửi yêu cầu đăng ký:", error.message);
    throw error; // Ném lỗi ra ngoài để xử lý
  }
};

// Hàm PUT
export const put = async (path, data) => {
  try {
    const response = await fetch(API + path, {
      method: "PUT",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
      },
      body: JSON.stringify(data),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }

    const result = await response.json();
    return result;
  } catch (error) {
    console.error("Error in PUT request:", error.message);
    throw error;
  }
};

// Hàm DELETE
export const remove = async (path) => {
  try {
    const response = await fetch(API + path, {
      method: "DELETE",
      headers: {
        Accept: "application/json",
      },
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Message: ${errorText}`);
    }

    const result = await response.json();
    return result;
  } catch (error) {
    console.error("Error in DELETE request:", error.message);
    throw error;
  }
};
